import{_ as i,o as a,c as n,ak as o,aK as d}from"./chunks/framework.DiS-pR0X.js";const v=JSON.parse('{"title":"1. Introduccion a IPv6","description":"","frontmatter":{"title":"1. Introduccion a IPv6","parent":"IPv6"},"headers":[],"relativePath":"redes/ipv6/intro.md","filePath":"redes/ipv6/intro.md","lastUpdated":1775409008000}'),r={name:"redes/ipv6/intro.md"};function t(s,e,c,l,p,u){return a(),n("div",null,[...e[0]||(e[0]=[o('<h1 id="internet-protocol-v6" tabindex="-1">Internet Protocol v6 <a class="header-anchor" href="#internet-protocol-v6" aria-label="Permalink to “Internet Protocol v6”">​</a></h1><h2 id="introduccion-a-ip-v6" tabindex="-1">Introducción a IP v6 <a class="header-anchor" href="#introduccion-a-ip-v6" aria-label="Permalink to “Introducción a IP v6”">​</a></h2><p><code>IPv6</code> significa <strong>Protocolo de Internet versión 6</strong> y es la versión más reciente del Protocolo de Internet utilizado para la comunicación de datos a través de internet. Es el sucesor del protocolo <code>IPv4</code>, que aún se utiliza ampliamente en la actualidad.</p><p><code>IPv6</code> se desarrolló para superar la limitación de <code>IPv4</code>, que tiene un número limitado de direcciones disponibles. Con el crecimiento exponencial de dispositivos y usuarios conectados a internet, las direcciones <code>IPv4</code> se están agotando.</p><p><code>IPv6</code> ofrece un espacio de direcciones de <strong>128 bits</strong> mucho mayor que el de <strong>32 bits</strong> de <code>IPv4</code> . Esto garantiza la disponibilidad de direcciones para el crecimiento futuro previsible de Internet.</p><p><code>IPv6</code> también tiene mejoras en enrutamiento, configuración de red, seguridad y rendimiento respecto a <code>IPv4</code>.</p><h2 id="¿como-funcionan-las-direcciones-ipv6" tabindex="-1">¿Cómo funcionan las direcciones IPv6? <a class="header-anchor" href="#¿como-funcionan-las-direcciones-ipv6" aria-label="Permalink to “¿Cómo funcionan las direcciones IPv6?”">​</a></h2><p>A continuación se ofrece una breve descripción general de cómo funcionan las direcciones IPv6:</p><ul><li>Las direcciones IPv6 son de 128 bits, a diferencia de las de 32 bits utilizadas en IPv4. Esto proporciona un espacio de direcciones mucho mayor, lo que permite potencialmente billones de direcciones IP únicas.</li><li>La dirección IPv6 de 128 bits se representa típicamente como 8 grupos de 4 dígitos hexadecimales separados por dos puntos. Por ejemplo, <code>2001:0db8:85a3:0000:0000:8a2e:0370:7334</code>.</li><li>Los ceros iniciales en cada grupo se pueden omitir, y los grupos sucesivos de ceros se pueden reemplazar por dos puntos, de la siguiente manera: <code>2001:db8:85a3::8a2e:370:7334</code></li><li>Las direcciones IPv6 se asignan en bloques, de forma similar al enrutamiento entre dominios sin clases (CIDR) de IPv4. La longitud del prefijo indica cuántos bits iniciales comunes comparten las direcciones del bloque.</li><li>IPv6 admite tanto direcciones unicast (para una única interfaz) como direcciones anycast (para un servicio proporcionado por múltiples interfaces).</li><li>Las direcciones de multidifusión permiten la transmisión de paquetes a múltiples interfaces. Comienzan con <code>ff00::/8</code>.</li><li>Las direcciones de enlace local se utilizan para la comunicación dentro de un segmento de red local y comienzan con <code>fe80::/10</code>.</li><li>IPv6 eliminó las direcciones de difusión. En su lugar, se utiliza una dirección de multidifusión local de enlace.</li><li>ICMPv6 (ICMP para IPv6) proporciona informes de errores y funciones de diagnóstico como ping, descubrimiento de vecinos, descubrimiento de enrutadores, etc.</li><li>Las conexiones IPv6 suelen utilizar IPsec para la seguridad de extremo a extremo en lugar de NAT. IPsec proporciona autenticación, integridad y confidencialidad.</li></ul><p>En resumen, el mayor espacio de direcciones, el encabezado simplificado, la seguridad mejorada y las nuevas características hacen que IPv6 sea ideal para la Internet moderna.</p><p>Pero tanto IPv4 como IPv6 siguen utilizándose ampliamente hoy en día durante este período de transición.</p><h2 id="diferencias-clave-entre-ipv4-e-ipv6" tabindex="-1">Diferencias clave entre IPv4 e IPv6 <a class="header-anchor" href="#diferencias-clave-entre-ipv4-e-ipv6" aria-label="Permalink to “Diferencias clave entre IPv4 e IPv6”">​</a></h2><p>A continuación se muestra una comparación de algunas diferencias clave entre IPv4 e IPv6:</p><table tabindex="0"><thead><tr><th>IPv4</th><th>IPv6</th></tr></thead><tbody><tr><td>Dirección de 32 bits</td><td>Dirección de 128 bits</td></tr><tr><td>Admite 340 billones de billones de billones de dispositivos</td><td>Admite 340 billones de billones de billones de dispositivos</td></tr><tr><td>Direccionamiento de red con clases complejas</td><td>Direccionamiento jerárquico simplificado</td></tr><tr><td>Priorización de tráfico limitado</td><td>Calidad de servicio incorporada</td></tr><tr><td>Seguridad básica con NAT</td><td>Seguridad de extremo a extremo con IPsec</td></tr><tr><td>Configuración manual del host</td><td>Configuración automática de direcciones</td></tr><tr><td>Opciones y extensiones limitadas</td><td>Opciones y extensiones flexibles</td></tr><tr><td>La fragmentación es procesada por el enrutador</td><td>La fragmentación es de extremo a extremo</td></tr><tr><td>Redes basadas en transmisión</td><td>Redes de multidifusión</td></tr><tr><td>Suma de comprobación en cada capa de red</td><td>Suma de comprobación solo en la capa de transporte</td></tr><tr><td>Escalabilidad de enrutamiento limitada</td><td>Enrutamiento jerárquico para una mejor escalabilidad</td></tr></tbody></table><hr><p>En resumen, IPv6 proporciona direccionamiento ampliado, enrutamiento mejorado, seguridad, rendimiento y gestión en comparación con IPv4.</p><h2 id="tipos-de-direcciones-ipv6" tabindex="-1">Tipos de direcciones IPv6 <a class="header-anchor" href="#tipos-de-direcciones-ipv6" aria-label="Permalink to “Tipos de direcciones IPv6”">​</a></h2><p>Hay varios tipos de direcciones IPv6 que se utilizan para diferentes propósitos:</p><ul><li>Unicast: Se dirige a una sola interfaz de red. Se utiliza para la mayoría de las comunicaciones.</li><li>Multidifusión: identifica un grupo de interfaces de red. Se utiliza en comunicaciones de uno a muchos.</li><li>Anycast: Identifica un grupo de interfaces. Se utiliza en comunicaciones de uno a la más cercana.</li><li>Bucle invertido: Lo utiliza un nodo para enviarse paquetes a sí mismo. Equivalente a <code>127.0.0.1</code> de IPv4.</li><li>Sin especificar: Indica la ausencia de una dirección. Equivalente a <code>0.0.0.0</code> de IPv4.</li><li>Enlace local: Se utiliza para comunicaciones dentro de un segmento o enlace de red lógico. Se configura automáticamente localmente.</li><li>Local único: Se utiliza como direcciones IP privadas en IPv4. No es enrutable en la internet global.</li></ul><p><img src="'+d+'" alt=""></p><h2 id="beneficios-clave-de-ipv6" tabindex="-1">Beneficios clave de IPv6 <a class="header-anchor" href="#beneficios-clave-de-ipv6" aria-label="Permalink to “Beneficios clave de IPv6”">​</a></h2><p>Estas son algunas de las principales ventajas que ofrece IPv6 sobre IPv4:</p><ul><li>Espacio de direcciones prácticamente ilimitado para el crecimiento futuro.</li><li>Arquitectura de enrutamiento eficiente y escalable.</li><li>El enrutamiento más rápido parece deberse a un encabezado simplificado.</li><li>Capacidades de seguridad y privacidad IPsec integradas.</li><li>Autoconfiguración para asignar direcciones IP automáticamente.</li><li>Multidifusión nativa y anycast para habilitar nuevas aplicaciones.</li><li>Mejor soporte para dispositivos que se conectan directamente a Internet.</li><li>Flexibilidad para agregar opciones y extensiones personalizadas.</li><li>Capacidades para priorizar y gestionar diferentes tipos de tráfico.</li><li>Soporte para dispositivos móviles y movilidad.</li></ul><h2 id="tendencias-de-implementacion-y-adopcion-de-ipv6" tabindex="-1">Tendencias de implementación y adopción de IPv6 <a class="header-anchor" href="#tendencias-de-implementacion-y-adopcion-de-ipv6" aria-label="Permalink to “Tendencias de implementación y adopción de IPv6”">​</a></h2><p>Si bien IPv6 se estandarizó en la década de 1990, su adopción ha cobrado impulso en la última década:</p><ul><li>Tráfico IPv6: se estima que representará alrededor del 30 % del tráfico mundial de Internet en 2022. Principalmente proveniente de dispositivos móviles.</li><li>Proveedores de servicios: La mayoría de los principales proveedores de servicios de internet han habilitado la conectividad IPv6. Sin embargo, muchos aún utilizan tecnologías de transición.</li><li>Sitios web: aproximadamente el 30% de los 1000 sitios web principales de Alexa son accesibles a través de IPv6, lo que representa un aumento respecto de menos del 5% hace una década.</li><li>Dispositivos y software: la mayoría de los equipos y software modernos son compatibles con IPv6. Los sistemas operativos móviles como Android e iOS son totalmente compatibles con IPv6.</li><li>Mandatos gubernamentales – Muchos gobiernos han establecido cronogramas y objetivos para la adopción de IPv6 en sus países.</li></ul><p>Por lo tanto, el uso de IPv6 está creciendo rápidamente a medida que se agotan las direcciones IPv4. Sin embargo, se espera que IPv4 coexista con IPv6 durante un largo período durante la transición.</p><h2 id="mecanismos-de-transicion-de-ipv6-a-ipv4" tabindex="-1">Mecanismos de transición de IPv6 a IPv4 <a class="header-anchor" href="#mecanismos-de-transicion-de-ipv6-a-ipv4" aria-label="Permalink to “Mecanismos de transición de IPv6 a IPv4”">​</a></h2><p>Dado que IPv4 está tan ampliamente implementado, la transición no es instantánea. A continuación, se presentan algunas técnicas para una transición gradual:</p><ul><li>Implementación de doble pila: las redes ejecutan IPv4 e IPv6 juntos y transfieren el tráfico entre ellas.</li><li>Tunelización: el tráfico IPv6 se encapsula dentro de paquetes IPv4 para enrutarlo a través de redes IPv4.</li><li>Traducción: conversión entre direcciones IPv6 e IPv4 para compatibilidad.</li><li>Reescritura de encabezados: los encabezados de paquetes IPv6 se modifican para que se parezcan a los paquetes IPv4.</li></ul><p>Estos mecanismos permiten que Internet cambie progresivamente hacia IPv6 manteniendo al mismo tiempo la compatibilidad con la infraestructura IPv4 existente durante la transición.</p><p>Articulo traducido de <a href="https://callwave.com/ipv6/" target="_blank" rel="noreferrer">https://callwave.com/ipv6/</a></p>',32)])])}const P=i(r,[["render",t]]);export{v as __pageData,P as default};
